#include <stdio.h>

int gcd(int a, int b) {
    if (a % b == 0) {
        return b;
    } else {
        return gcd(b, a % b);
    }
}

int main() {
    int t1, t2, x1, x2, t0;
    scanf("%d %d %d %d %d", &t1, &t2, &x1, &x2, &t0);
    int a = t2 - t0;
    int b = t0 - t1;
    if (a == 0 && b == 0) {
        printf("%d %d\n", x1, x2);
        return 0;
    }
    if (a == 0) {
        printf("0 %d\n", x2);
        return 0;
    }
    if (b == 0) {
        printf("%d 0\n", x1);
        return 0;
    }
    int g = gcd(a, b);
    a /= g;
    b /= g;
    if (a <= x1 && b <= x2) {
        int mintime = (x1 / a < x2 / b) ? x1 / a : x2 / b;
        printf("%d %d\n", mintime * a, mintime * b);
        return 0;
    }
    int y1 = 1;
    int y2 = 1;
    int miny1 = 1;
    int miny2 = 1;
    double minn = 99999;
    int fg = 0;
    while (y1 <= x1 && y2 <= x2) {
        if ((double)y1 / y2 < (double)a / b) {
            if (minn > (double)a / b - (double)y1 / y2) {
                minn = (double)a / b - (double)y1 / y2;
                miny1 = y1;
                miny2 = y2;
                fg = 1;
            }
            y1++;
        } else {
            y2++;
        }
    }
    y1 = miny1;
    y2 = miny2;
    int mintime = (x1 / y1 < x2 / y2) ? x1 / y1 : x2 / y2;
    if (fg == 1) {
        printf("%d %d\n", mintime * y1, mintime * y2);
    } else {
        printf("0 %d\n", x2);
    }
    return 0;
}
